mapper.select:
SELECT id, name, role, phone, email, password, email_hash, phone_hash
FROM user
WHERE id = #{id}

mapper.update:
UPDATE user
name = #{name}, role = #{role}, phone = #{phone, typeHandler=org.example.housebackend.typehandler.EncryptedStringTypeHandler}, email = #{email, typeHandler=org.example.housebackend.typehandler.EncryptedStringTypeHandler}, password = #{password}, email_hash = #{emailHash}, phone_hash = #{phoneHash},
WHERE id = #{id}
